import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const b=JSON.parse('{"title":"Claude Code 兩個新 Skills：/simplify 與 /batch — @bcherny","description":"","frontmatter":{"title":"Claude Code 兩個新 Skills：/simplify 與 /batch — @bcherny","author":"Boris Cherny（@bcherny）","date":"2026-02-28T00:00:00.000Z","source":"https://x.com/bcherny/status/2027534984534544489","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-02-28-@bcherny-544489.md","filePath":"research/tweets/2026-02-28-@bcherny-544489.md","lastUpdated":1779894392000}'),l={name:"research/tweets/2026-02-28-@bcherny-544489.md"};function i(d,e,s,c,h,n){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="claude-code-兩個新-skills-simplify-與-batch-—-bcherny" tabindex="-1">Claude Code 兩個新 Skills：/simplify 與 /batch — @bcherny <a class="header-anchor" href="#claude-code-兩個新-skills-simplify-與-batch-—-bcherny" aria-label="Permalink to &quot;Claude Code 兩個新 Skills：/simplify 與 /batch — @bcherny&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/bcherny/status/2027534984534544489" target="_blank" rel="noreferrer">https://x.com/bcherny/status/2027534984534544489</a><strong>作者</strong>：Boris Cherny（@bcherny） <strong>發布日期</strong>：2026-02-28 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文（Note Tweet） <strong>統計</strong>：12941 likes · 845 retweets · 0 bookmarks · 2527128 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>In the next version of Claude Code..</p><p>We&#39;re introducing two new Skills: /simplify and /batch. I have been using both daily, and am excited to share them with everyone.</p><p>Combined, these skills automate much of the work it used to take to (1) shepherd a pull request to production and (2) perform straightforward, parallelizable code migrations.</p><p>（附圖：示意截圖 <a href="https://x.com/bcherny/status/2027534984534544489/photo/1%EF%BC%89" target="_blank" rel="noreferrer">https://x.com/bcherny/status/2027534984534544489/photo/1）</a></p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude Code 官方釋出 <code>/simplify</code>（PR 品質審查）與 <code>/batch</code>（平行代碼遷移）兩個新 Skill，由作者日常使用驗證。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li><code>/simplify</code> Skill 負責 code review + 品質優化，自動化 PR shepherd 流程的一大核心工作</li><li><code>/batch</code> Skill 負責平行可拆解的代碼遷移任務（parallelizable migrations）</li><li>兩者合計涵蓋 PR 生命週期從撰寫到上線、跨模組批次遷移兩大工程痛點</li><li>Boris Cherny（Claude Code 直接作者）個人日常使用，代表官方認可的使用模式</li><li>這是官方 Skill 而非社群貢獻，具有最高可信度與可攜性</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li><strong>12,941 likes · 2,527,128 views</strong>：高度傳播，Claude Code 社群主要參考資訊</li><li><code>/simplify</code>：review code for reuse, quality, efficiency；已整合進本 workspace</li><li><code>/batch</code>：parallelizable code migrations；fan-out 多個 subagent 各自處理遷移目標</li><li>作者：Boris Cherny，@anthropicai Claude Code 負責人</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>推文本身為公告性質，技術細節見後續 Skills 實作（tweet 截斷，無 PR 流程詳細說明）</li><li><code>/simplify</code> 與 <code>/batch</code> 均已可在 cc-workspace 中觀察到（本 workspace 已有 <code>simplify</code> skill）</li><li><code>is_note_tweet: true</code> 但 fxtwitter 只回傳了截斷版本（342 字元），完整 Note Tweet 內容可能包含更多實作細節</li><li>「parallelizable code migrations」是 <code>/batch</code> 的關鍵限制：僅適合可分解、無相互依賴的遷移任務</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>9/10</td><td>官方 Skills 可直接採用，本 workspace 已有 simplify；batch 為可評估的新增目標</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>概念清晰但非深度原創；PR shepherd + 平行遷移是已知痛點，官方封裝有價值</td></tr><tr><td>C. 證據品質 (20%)</td><td>8/10</td><td>作者本人日常使用 + 12K likes 社群驗證；但缺乏量化效率數據</td></tr><tr><td>D. 技術深度 (15%)</td><td>5/10</td><td>公告推文，技術細節少；完整 Note Tweet 可能更豐富但未能取得</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>PR 流程與代碼遷移是通用工程需求，跨任何 codebase 均適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.65/10</strong></td><td>9×0.3+7×0.2+8×0.2+5×0.15+8×0.15 = 2.7+1.4+1.6+0.75+1.2 = 7.65</td></tr></tbody></table><p><strong>整合決策</strong>：SKILL <strong>理由</strong>：官方 <code>/simplify</code> 與 <code>/batch</code> 均為高可行動性 Skills，<code>simplify</code> 已存在於本 workspace，<code>batch</code> 值得評估引入。</p>',21)])])}const u=t(l,[["render",i]]);export{b as __pageData,u as default};
